@@ -138,7 +138,7 @@ function notif(text, colour) {
         text: '',
         font: {size: sizeData[DEFAULT_SIZE].size},
         x: 0,
-        y: Window.innerHeight,
+        y: Overlays.height(),
         color: colour.text,
